   553	func importParenDelta(line []byte, inBlockComment bool) (delta int, hasParen bool, nextInBlockComment bool) {
   554		nextInBlockComment = inBlockComment
   555		for i := 0; i < len(line); i++ {
   556			if nextInBlockComment {
   557				if i+1 < len(line) && line[i] == '*' && line[i+1] == '/' {
   558					nextInBlockComment = false
   559					i++
   560				}
   561				continue
   562			}
   563	
