   233	func refreshOrderedFields(fields, ordered []Field, include func(Field) bool) []Field {
   234		fieldByColumn := make(map[string]Field, len(fields))
   235		included := make([]Field, 0, len(fields))
   236		for i := range fields {
   237			field := fields[i]
   238			if !include(field) {
   239				continue
   240			}
   241			fieldByColumn[field.ColumnName] = field
   242			included = append(included, field)
   243		}
   244		if len(ordered) == 0 {
   245			return included
   246		}
   247	
   248		out := make([]Field, 0, len(included))
   249		seen := make(map[string]struct{}, len(included))
   250		for _, field := range ordered {
   251			refreshed, ok := fieldByColumn[field.ColumnName]
   252			if !ok {
   253				continue
   254			}
   255			out = append(out, refreshed)
   256			seen[field.ColumnName] = struct{}{}
   257		}
   258		for _, field := range included {
   259			if _, ok := seen[field.ColumnName]; ok {
   260				continue
   261			}
   262			out = append(out, field)
   263		}
   264		return out
   265	}
   266	
   267	func dedupeImportSpecs(imports []ImportSpec) []ImportSpec {
   268		seen := make(map[string]ImportSpec)
   269		for _, spec := range imports {
   270			if spec.Path == "" {
   271				continue
   272			}
   273			existing, ok := seen[spec.Path]
   274			// Prefer an explicit alias over an inferred bare import for the same path.
   275			if !ok || (existing.Alias == "" && spec.Alias != "") {
   276				seen[spec.Path] = spec
   277			}
   278		}
   279	
   280		out := make([]ImportSpec, 0, len(seen))
   281		for _, spec := range seen {
   282			out = append(out, spec)
   283		}
   284	
   285		sort.Slice(out, func(i, j int) bool {
   286			return out[i].Path < out[j].Path
   287		})
   288		return out
   289	}
