   298	func inferImportSpecsFromTypeExpr(expr string) []ImportSpec {
   299		matches := typeQualifierPattern.FindAllStringSubmatch(expr, -1)
   300		specs := make([]ImportSpec, 0, len(matches))
   301		for _, match := range matches {
   302			if len(match) < 2 {
   303				continue
   304			}
   305			if path, ok := knownImportAliases[match[1]]; ok {
   306				specs = append(specs, ImportSpec{Path: path})
   307			}
   308		}
   309		return dedupeImportSpecs(specs)
   310	}

